// pubspec: go_router: ^14.6.2
import 'package:flutter/material.dart';
import 'package:go_router/go_router.dart';

class Auth { static bool loggedIn = false; }

final _router = GoRouter(
  routes: [
    GoRoute(path: '/', builder: (_, __) => const _Home()),
    GoRoute(
      path: '/product/:id',
      builder: (context, state) => _Detail(id: state.pathParameters['id']!),
    ),
    GoRoute(path: '/login', builder: (_, __) => const _Login()),
  ],
  redirect: (context, state) {
    final protecting = state.matchedLocation.startsWith('/product');
    if (protecting && !Auth.loggedIn) return '/login';
    return null;
  },
);

void main() => runApp(MaterialApp.router(routerConfig: _router));

class _Home extends StatelessWidget {
  const _Home();
  @override
  Widget build(BuildContext c) => Scaffold(
    appBar: AppBar(title: const Text('Home')),
    body: Center(child: FilledButton(
      onPressed: () => c.push('/product/42'),
      child: const Text('Open product 42'),
    )),
  );
}

class _Detail extends StatelessWidget {
  const _Detail({required this.id});
  final String id;
  @override
  Widget build(BuildContext c) => Scaffold(
    appBar: AppBar(title: Text('Product $id')),
    body: Center(child: Text('details for $id')),
  );
}

class _Login extends StatelessWidget {
  const _Login();
  @override
  Widget build(BuildContext c) => Scaffold(
    appBar: AppBar(title: const Text('Login')),
    body: Center(child: FilledButton(
      onPressed: () { Auth.loggedIn = true; c.go('/'); },
      child: const Text('Log in'),
    )),
  );
}

// Try:
//   * Tap 'Open product 42' ŌĆö redirected to /login.
//   * Log in ŌĆö bounced back to /.
//   * Tap 'Open product 42' again ŌĆö now the detail page shows.
//   * `adb shell am start -a android.intent.action.VIEW -d 'myapp://product/42'`
//     with the intent-filter set up ŌåÆ app opens directly on the product page.

